"use client";

import { useState } from "react";

export default function AddRecordForm() {
  const [form, setForm] = useState({
    patientId: "",
    disease: "",
    symptoms: "",
    prescription: "",
    hospitalName: "",
  });

  const [file, setFile] = useState<File | null>(null);

  const handleChange = (e: any) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async () => {
    try {
      const formData = new FormData();

      formData.append("patientId", form.patientId);
      formData.append("disease", form.disease);
      formData.append(
        "symptoms",
        JSON.stringify(form.symptoms.split(","))
      );
      formData.append("prescription", form.prescription);
      formData.append("hospitalName", form.hospitalName);

      if (file) {
        formData.append("report", file);
      }

      const res = await fetch(
        "http://localhost:5000/api/records/add",
        {
          method: "POST",
          headers: {
            Authorization: `Bearer ${localStorage.getItem("token")}`,
          },
          body: formData,
        }
      );

      const data = await res.json();

      alert("Record added successfully 🚀");
      console.log(data);
    } catch (error) {
      console.error(error);
      alert("Failed to add record");
    }
  };

  return (
    <div className="bg-white p-4 rounded shadow space-y-3">
      <input name="patientId" placeholder="Patient ID" onChange={handleChange} className="input" />
      <input name="disease" placeholder="Disease" onChange={handleChange} className="input" />
      <input name="symptoms" placeholder="Symptoms (comma separated)" onChange={handleChange} className="input" />
      <input name="prescription" placeholder="Prescription" onChange={handleChange} className="input" />
      <input name="hospitalName" placeholder="Hospital Name" onChange={handleChange} className="input" />

      <input
        type="file"
        onChange={(e) => setFile(e.target.files?.[0] || null)}
        className="input"
      />

      <button
        onClick={handleSubmit}
        className="w-full bg-green-600 text-white py-2 rounded"
      >
        Submit Record
      </button>
    </div>
  );
}